(()=>{'use strict';
const T=v=>String(v??'').trim(),N=v=>Number(String(v??'').replace(/,/g,''))||0,F=n=>N(n).toLocaleString('th-TH'),B=n=>N(n).toLocaleString('th-TH',{minimumFractionDigits:2,maximumFractionDigits:2});
let rows=[],meta={},lastPayload=null;
function $(s){return document.querySelector(s)}
function esc(s){return T(s).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}
function datestr(s){const p=T(s).split('-');return p.length===3?`${p[2]}/${p[1]}/${p[0]}`:s}
function filters(){return{start:T($('#startDate')?.value),end:T($('#endDate')?.value),ps:T($('#psSelect')?.value)}}
function stateKey(){return 'doit-json:'+(meta.id||lastPayload?.version_id||meta.file_name||'')}
function state(){try{return JSON.parse(localStorage.getItem(stateKey())||'{}')}catch{return{}}}
function pk(r){return [r.brand,r.size,r.code||r.sku,r.sku,r.type].join('|')}
function scopeRows(){const f=filters();return rows.filter(r=>(!f.start||r.date>=f.start)&&(!f.end||r.date<=f.end)&&(!f.ps||r.ps===f.ps))}
function group(){const m=new Map();scopeRows().forEach(r=>{const k=pk(r);let g=m.get(k);if(!g){g={poolKey:k,brand:r.brand,size:r.size,code:r.code,sku:r.sku,type:r.type,qty:0,amt:0,unit:r.unit||0};m.set(k,g)}g.qty+=N(r.qty);g.amt+=N(r.amt);g.unit=g.qty&&g.amt?g.amt/g.qty:g.unit});return m}
function recFromKey(k){return String(k).split('|')[3]||''}
function pkFromKey(k){return String(k).split('|').slice(4).join('|')}
function scopeHead(){const f=filters();return[f.start,f.end,f.ps].join('|')+'|'}
function lines(){const st=state(),send=st.send||{},gmap=group(),out=[];Object.keys(send).filter(k=>k.startsWith(scopeHead())).forEach(k=>{const q=N(send[k]);if(q<=0)return;const g=gmap.get(pkFromKey(k));const rec=recFromKey(k);if(g&&rec)out.push({store:rec,code:g.code||'',name:g.sku,brand:g.brand,size:g.size,type:g.type,qty:q,unit:g.unit||0})});return out}
function exportCsv(e){e?.preventDefault?.();e?.stopImmediatePropagation?.();const f=filters(),out=[['receiver','date_start','date_end','ps','brand','size','sku_code','product','type','send_qty','unit_price','line_total']];lines().forEach(l=>out.push([l.store,f.start,f.end,f.ps,l.brand,l.size,l.code,l.name,l.type,l.qty,l.unit,l.qty*l.unit]));if(out.length===1){alert('ยังไม่มีจำนวนส่งจริงให้ Export');return}const csv='\ufeff'+out.map(a=>a.map(x=>'"'+String(x??'').replace(/"/g,'""')+'"').join(',')).join('\n');const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([csv],{type:'text/csv;charset=utf-8'}));a.download='doit-delivery-orders.csv';a.click()}
function printForm(e){e?.preventDefault?.();e?.stopImmediatePropagation?.();const data=lines();if(!data.length){alert('ยังไม่ได้ใส่จำนวนส่งจริงให้ร้านใด');return}const by={};data.forEach(l=>(by[l.store]??=[]).push(l));const w=window.open('','_blank');if(!w){alert('เบราว์เซอร์บล็อกหน้าปริ้น');return}const d=w.document;d.body.innerHTML='';d.title='แบบฟอร์มใบส่งสินค้า';const style=d.createElement('style');style.textContent='@page{size:A4;margin:8mm}body{font-family:Tahoma,Arial,sans-serif;margin:0;background:#eee}.bar{position:sticky;top:0;background:#087b34;color:white;padding:10px}.bar button{font-weight:900;padding:8px 14px}.page{background:white;width:194mm;min-height:281mm;margin:10px auto;padding:8mm;page-break-after:always}.head{display:flex;justify-content:space-between;border-bottom:2px solid #111;margin-bottom:8px;padding-bottom:6px}.shop{font-size:16px;font-weight:900}table{width:100%;border-collapse:collapse;font-size:12px}th,td{border:1px solid #111;padding:4px}th{background:#eee}.r{text-align:right}.price{width:75px;text-align:right}.sign{display:grid;grid-template-columns:1fr 1fr 1fr;gap:16px;margin-top:24px;text-align:center}.sign div{border-top:1px solid #111;padding-top:6px}@media print{body{background:white}.bar{display:none}.page{margin:0}.price{border:0}}';d.head.appendChild(style);const bar=d.createElement('div');bar.className='bar';bar.innerHTML='<b>แก้ราคา/หน่วยก่อน แล้วค่อยกดสั่งปริ้น</b> ';const btn=d.createElement('button');btn.textContent='สั่งปริ้น';bar.appendChild(btn);d.body.appendChild(bar);const f=filters();Object.entries(by).forEach(([store,items],bi)=>{const pg=d.createElement('section');pg.className='page';pg.innerHTML=`<div class="head"><div><b>ใบส่งสินค้า</b><div class="shop">ร้าน: ${esc(store)}</div></div><div>วันที่: ${esc(datestr(f.end||f.start))}<br>PS: ${esc(f.ps||'ทั้งหมด')}<br>ใบที่: ${bi+1}</div></div><table><thead><tr><th>#</th><th>รหัส</th><th>รายการ</th><th>จำนวน</th><th>ราคา/หน่วย</th><th>รวม</th></tr></thead><tbody></tbody></table><div class="sign"><div>ผู้จัดของ</div><div>ผู้ส่ง</div><div>ผู้รับสินค้า</div></div>`;const tb=pg.querySelector('tbody');items.forEach((l,i)=>{const tr=d.createElement('tr');tr.innerHTML=`<td>${i+1}</td><td>${esc(l.code)}</td><td>${esc(l.name)}<br><small>${esc(l.brand)} · ${esc(l.size)} · ${esc(l.type)}</small></td><td class="r">${F(l.qty)}</td><td class="r"></td><td class="r total">0.00</td>`;const inp=d.createElement('input');inp.className='price';inp.type='number';inp.step='0.01';inp.value=String(Math.round(N(l.unit)*100)/100);inp.dataset.qty=l.qty;tr.children[4].appendChild(inp);tb.appendChild(tr)});tb.insertAdjacentHTML('beforeend','<tr><td colspan="5" class="r"><b>รวม</b></td><td class="r billTotal">0.00</td></tr>');d.body.appendChild(pg)});function recalc(){d.querySelectorAll('.page').forEach(pg=>{let sum=0;pg.querySelectorAll('.price').forEach(inp=>{const v=N(inp.value)*N(inp.dataset.qty);sum+=v;inp.closest('tr').querySelector('.total').textContent=B(v)});pg.querySelector('.billTotal').textContent=B(sum)})}d.querySelectorAll('.price').forEach(i=>i.oninput=recalc);btn.onclick=()=>{recalc();w.print()};recalc()}
function guardRedo(e){if(window.__doitRedoSafe)return;window.__doitRedoSafe=1;setTimeout(()=>{window.__doitRedoSafe=0},150);try{document.querySelector('#redo')?.onclick?.call(document.querySelector('#redo'),e)}catch(err){e?.preventDefault?.();e?.stopImmediatePropagation?.();alert('Redo มีปัญหาจาก cache เก่า ให้รีเฟรชหน้าแล้วลองใหม่')}}
function installButtons(){const p=$('#prepPrint'),x=$('#exportCsv'),r=$('#redo');if(p&&!p.dataset.fix267){p.dataset.fix267='1';p.addEventListener('click',printForm,true)}if(x&&!x.dataset.fix267){x.dataset.fix267='1';x.addEventListener('click',exportCsv,true)}if(r&&!r.dataset.fix267){r.dataset.fix267='1';r.addEventListener('click',guardRedo,true)}}
function wrap(){if(!window.DOIT_JSON_APP||window.DOIT_JSON_APP.__printFix267)return false;const app=window.DOIT_JSON_APP,old=app.load.bind(app);app.load=(payload,m={})=>{lastPayload=payload;meta=m||{};rows=(payload.rows||payload||[]).map(r=>({date:T(r.date),ps:T(r.ps),code:T(r.code),sku:T(r.sku),brand:T(r.brand),size:T(r.size),type:T(r.type)||'INVC',qty:N(r.qty),unit:N(r.unit),amt:N(r.amt)}));old(payload,m);setTimeout(installButtons,80)};app.__printFix267=true;return true}
function boot(){installButtons();if(!wrap())setTimeout(boot,300)}document.addEventListener('DOMContentLoaded',boot);if(document.readyState!=='loading')boot();})();